const express = require('express');
const jwt = require('jsonwebtoken');
const session = require('express-session');
const fetch = require('node-fetch');

const app = express();
app.use(express.json());
app.use(session({
    secret: 'your_secret_key',
    resave: false,
    saveUninitialized: true,
    cookie: { secure: true } // Ensure cookies are sent over HTTPS
}));

const OIDC_PROVIDER_URL = 'https://your-oidc-provider.com';
const CLIENT_ID = 'your_client_id';
const CLIENT_SECRET = 'your_client_secret';
const REDIRECT_URI = 'https://yourapp.com/callback';

app.get('/login', (req, res) => {
    const authorizationUrl = `${OIDC_PROVIDER_URL}/authorize?response_type=id_token&client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&scope=openid`;
    res.redirect(authorizationUrl);
});

app.get('/callback', async (req, res) => {
    const idToken = req.query.id_token;

    if (!idToken) {
        return res.status(400).send('ID token is missing');
    }

    // Decode the ID token to extract user claims
    const decodedToken = jwt.decode(idToken);
    
    if (!decodedToken) {
        return res.status(400).send('Invalid ID token');
    }

    // Create user session using extracted claims
    req.session.user = {
        id: decodedToken.sub,
        name: decodedToken.name,
        email: decodedToken.email
    };

    res.send('Login successful');
});

app.listen(3000, () => {
    console.log('Server is running on port 3000');
});

